package practice.basic;

import java.util.Map;
import java.util.stream.Collectors;

public class Occurences {
    public static void main(String[] args) {
        String s = "mediterranean";
        System.out.println(test());
    }

    static Map<Character,Long> test(){
        return "ANKITKONCHADY".chars()
                .mapToObj(c -> (char)c)
                .collect(Collectors.groupingBy(c->c,Collectors.counting()));
    }
}

package practice.basic;

import java.util.Map;
import java.util.stream.Collectors;

public class Occurences {
    public static void main(String[] args) {
        String s = "mediterranean";
        Map<Character, Long> occurrences = getCharacterOccurrences(s);
        System.out.println("Character occurrences in '" + s + "': " + occurrences);
    }

    // Return a map with character occurrences using Stream API
    static Map<Character, Long> getCharacterOccurrences(String input) {
        return input.chars()
                .mapToObj(c -> (char) c)
                .collect(Collectors.groupingBy(c -> c, Collectors.counting()));
    }
}

package practice.basic;

import java.util.*;

public class SecondHighestSalary {

    public static void main(String[] args) {
       Employee employee1 = new Employee("Ankit",1000L);
       Employee employee2 = new Employee("Snehal",10000L);
       Employee employee3 = new Employee("Hemant",13000L);
       Employee employee4 = new Employee("Veena",15000L);

         List<Employee> employees = Arrays.asList(employee1,employee2,employee3,employee4);

         String secondHighestSalaryEmployeeName = employees.stream()
                    .sorted(Comparator.comparingLong(Employee::getSalary).reversed())
                    .skip(1)
                    .findFirst()
                    .map(Employee::getName)
                    .orElse("No employee found");

        System.out.println(secondHighestSalaryEmployeeName);

        long secondHighestSalary = employees.stream()
                .map(Employee::getSalary)
                .sorted(Collections.reverseOrder())
                .limit(2)
                .skip(1)
                .findFirst()
                .orElse(-1L);

        System.out.println("Salary : " + secondHighestSalary);

    }
}

class Employee{

    private String name;
    private long salary;

    public Employee(String name, long salary) {
        this.name = name;
        this.salary = salary;
    }

    public String getName() {
        return name;
    }

    public long getSalary() {
        return salary;
    }

}

package practice.basic;

import java.util.*;

public class SecondHighestSalary {

    public static void main(String[] args) {
       Employee employee1 = new Employee("Ankit",1000L);
       Employee employee2 = new Employee("Snehal",10000L);
       Employee employee3 = new Employee("Hemant",13000L);
       Employee employee4 = new Employee("Veena",15000L);

         List<Employee> employees = Arrays.asList(employee1,employee2,employee3,employee4);

         // Get employee with second highest salary
         Employee secondHighestEmployee = employees.stream()
                    .sorted(Comparator.comparingLong(Employee::getSalary).reversed())
                    .skip(1)
                    .findFirst()
                    .orElse(null);

        if (secondHighestEmployee != null) {
            System.out.println("Employee Name: " + secondHighestEmployee.getName());
            System.out.println("Salary: " + secondHighestEmployee.getSalary());
        } else {
            System.out.println("No employee found");
        }

    }
}

class Employee{

    private String name;
    private long salary;

    public Employee(String name, long salary) {
        this.name = name;
        this.salary = salary;
    }

    public String getName() {
        return name;
    }

    public long getSalary() {
        return salary;
    }

}
